const errors = [];
for (const field of ['run_id', 'task_id', 'goal', 'criteria', 'iteration', 'instruction', 'status']) {
  if ($json[field] === undefined || $json[field] === null || $json[field] === '') {
    errors.push(`${field} is required`);
  }
}
if (!Array.isArray($json.criteria) || $json.criteria.length === 0) {
  errors.push('criteria must contain at least one item');
}
return [{ json: { ...$json, validation_errors: errors } }];

const input = $json;

const context =
  input.context && typeof input.context === 'object'
    ? input.context
    : {};

const agentMode =
  typeof input.agent_mode === 'string' && input.agent_mode.trim()
    ? input.agent_mode.trim()
    : typeof context.agent_mode === 'string' && context.agent_mode.trim()
      ? context.agent_mode.trim()
      : 'mock';

return [
  {
    json: {
      ...input,
      context: {
        ...context,
        agent_mode: agentMode,
      },
      prompt_reference: 'src/prompts/subagent_prompt.md',
      prompt_contract: {
        output: 'result.schema.json',
        format: 'json_only',
      },
      agent_mode: agentMode,
    },
  },
];

if (($json.validation_errors || []).length > 0) {
  return [{
    json: {
      run_id: $json.run_id || 'unknown',
      task_id: $json.task_id || 'unknown',
      status: 'failed',
      summary: 'Task validation failed before execution.',
      artifacts: [],
      known_issues: $json.validation_errors,
      evidence: ($json.criteria || ['task payload']).map((criterion) => ({
        criterion,
        status: 'fail',
        detail: 'Executor could not run because the task payload was invalid.'
      })),
      next_action_suggestion: 'Fix the task payload and retry.',
      error: {
        code: 'TASK_VALIDATION_FAILED',
        message: $json.validation_errors.join('; ')
      }
    }
  }];
}

const evidence = ($json.criteria || []).map((criterion, index) => ({
  criterion,
  status: index < 2 ? 'pass' : 'fail',
  detail: index < 2
    ? `Mock executor produced evidence for criterion ${index + 1}.`
    : `Mock executor intentionally leaves criterion ${index + 1} unresolved.`
}));

return [{
  json: {
    run_id: $json.run_id,
    task_id: $json.task_id,
    status: evidence.every((item) => item.status === 'pass') ? 'completed' : 'partial',
    summary: 'Mock executor completed one bounded task iteration.',
    artifacts: ['docs/WORKFLOW_DESIGN.md'],
    known_issues: evidence.filter((item) => item.status !== 'pass').map((item) => item.detail),
    evidence,
    next_action_suggestion: 'Run Criteria Checker to assess whether another iteration is required.',
    error: null
  }
}];

const agentOutput = $json || {};

let taskInput = {};
try {
  taskInput = $('Task Validator').item.json || {};
} catch (error) {
  taskInput = {};
}

const context =
  taskInput.context && typeof taskInput.context === 'object'
    ? taskInput.context
    : agentOutput.context && typeof agentOutput.context === 'object'
      ? agentOutput.context
      : {};

const runId =
  taskInput.run_id ||
  agentOutput.run_id ||
  `gd_${Date.now()}`;

const taskId =
  taskInput.task_id ||
  agentOutput.task_id ||
  `task_${Date.now()}`;

const goal =
  typeof taskInput.goal === 'string'
    ? taskInput.goal
    : typeof agentOutput.goal === 'string'
      ? agentOutput.goal
      : '';

const criteria = Array.isArray(taskInput.criteria)
  ? taskInput.criteria
  : Array.isArray(agentOutput.criteria)
    ? agentOutput.criteria
    : [];

const iteration =
  Number.isInteger(taskInput.iteration)
    ? taskInput.iteration
    : Number.isInteger(agentOutput.iteration)
      ? agentOutput.iteration
      : 1;

const artifacts = Array.isArray(agentOutput.artifacts)
  ? agentOutput.artifacts
  : [];

const knownIssues = Array.isArray(agentOutput.known_issues)
  ? agentOutput.known_issues
  : [];

const evidence = Array.isArray(agentOutput.evidence)
  ? agentOutput.evidence
  : [];

return [
  {
    json: {
      ...taskInput,
      ...agentOutput,

      run_id: runId,
      task_id: taskId,
      goal,
      criteria,
      context,
      iteration,

      agent_result: {
        run_id: runId,
        task_id: taskId,
        status: agentOutput.status || 'mock_completed',
        summary: agentOutput.summary || 'Mock agent execution completed.',
        artifacts,
        known_issues: knownIssues,
        evidence,
      },

      execution_log: {
        logged_at: new Date().toISOString(),
        summary: agentOutput.summary || 'Mock agent execution completed.',
        artifact_count: artifacts.length,
        issue_count: knownIssues.length,
        criteria_count: criteria.length,
      },
    },
  },
];
